export class AttachmentsService {
  /**
   * Upload or create an attachment
   *
   * Creates an attachment either by uploading a binary file (multipart/form-data)
   * or by providing a source URL for the server to download (application/json).
   *
   * **Multipart upload**: Uploads a binary file and stores it server-side.
   *
   * **URL-based creation**: Provides a `sourceUrl` for the server to download
   * asynchronously. Returns immediately with status `downloading`. The
   * attachment transitions to `ready` once the download completes, or `failed`
   * on error.
   *
   * Uploaded attachments expire after the specified duration unless they are
   * linked to an entry before expiration.
   */
  public static uploadAttachment<ThrowOnError extends boolean = true>(
    parameters: {
      expiresIn?: string;
      createFromUrlRequest: CreateFromUrlRequest;
    },
    options?: Options<never, ThrowOnError>,
  ) {
    const params = buildClientParams(
      [parameters],
      [
        {
          args: [
            { in: "query", key: "expiresIn" },
            { key: "createFromUrlRequest", map: "body" },
          ],
        },
      ],
    );
    return (options?.client ?? client).post<UploadAttachmentResponses, UploadAttachmentErrors, ThrowOnError, "data">({
      responseStyle: "data",
      security: [{ scheme: "bearer", type: "http" }],
      url: "/v1/attachments",
      ...options,
      ...params,
      headers: {
        "Content-Type": "application/json",
        ...options?.headers,
        ...params.headers,
      },
    });
  }

  /**
   * Delete an unlinked attachment
   *
   * Deletes an attachment that has not yet been linked to an entry.
   *
   * - Only the original uploader can delete an attachment.
   * - Only unlinked attachments (those without an `entryId`) can be deleted.
   * - Linked attachments return 409 Conflict since they are permanent.
   * - The file is removed from storage first, then the metadata record is deleted.
   */
  public static deleteAttachment<ThrowOnError extends boolean = true>(
    parameters: {
      id: string;
    },
    options?: Options<never, ThrowOnError>,
  ) {
    const params = buildClientParams([parameters], [{ args: [{ in: "path", key: "id" }] }]);
    return (options?.client ?? client).delete<DeleteAttachmentResponses, DeleteAttachmentErrors, ThrowOnError, "data">({
      responseStyle: "data",
      security: [{ scheme: "bearer", type: "http" }],
      url: "/v1/attachments/{id}",
      ...options,
      ...params,
    });
  }

  /**
   * Retrieve an attachment
   *
   * Downloads the binary content of an attachment.
   *
   * - If the attachment is unlinked (not yet associated with an entry), only
   * the original uploader can access it.
   * - If linked to an entry, anyone with read access to the conversation can
   * access it.
   * - If the FileStore supports signed URLs (e.g., S3), a 302 redirect is
   * returned instead of streaming the bytes directly.
   */
  public static getAttachment<ThrowOnError extends boolean = true>(
    parameters: {
      id: string;
      disposition?: "inline" | "attachment";
    },
    options?: Options<never, ThrowOnError>,
  ) {
    const params = buildClientParams(
      [parameters],
      [
        {
          args: [
            { in: "path", key: "id" },
            { in: "query", key: "disposition" },
          ],
        },
      ],
    );
    return (options?.client ?? client).get<GetAttachmentResponses, GetAttachmentErrors, ThrowOnError, "data">({
      responseStyle: "data",
      security: [{ scheme: "bearer", type: "http" }],
      url: "/v1/attachments/{id}",
      ...options,
      ...params,
    });
  }

  /**
   * Get a signed download URL for an attachment
   *
   * Returns a time-limited, signed URL that can be used to download the
   * attachment without an Authorization header. This is useful for opening
   * files in new browser tabs or triggering downloads.
   *
   * - For S3 storage: returns the S3 pre-signed URL directly.
   * - For DB storage: returns a server-relative URL with an HMAC-signed token.
   *
   * Access control is the same as `GET /v1/attachments/{id}`.
   */
  public static getAttachmentDownloadUrl<ThrowOnError extends boolean = true>(
    parameters: {
      id: string;
      disposition?: "inline" | "attachment";
    },
    options?: Options<never, ThrowOnError>,
  ) {
    const params = buildClientParams(
      [parameters],
      [
        {
          args: [
            { in: "path", key: "id" },
            { in: "query", key: "disposition" },
          ],
        },
      ],
    );
    return (options?.client ?? client).get<
      GetAttachmentDownloadUrlResponses,
      GetAttachmentDownloadUrlErrors,
      ThrowOnError,
      "data"
    >({
      responseStyle: "data",
      security: [{ scheme: "bearer", type: "http" }],
      url: "/v1/attachments/{id}/download-url",
      ...options,
      ...params,
    });
  }

  /**
   * Download an attachment via signed token
   *
   * Serves the binary content of an attachment using a time-limited signed
   * token. No authentication header is required.
   *
   * The token is obtained from `GET /v1/attachments/{id}/download-url`.
   * Returns 403 if the token is invalid or expired.
   */
  public static downloadAttachmentByToken<ThrowOnError extends boolean = true>(
    parameters: {
      token: string;
      filename: string;
      disposition?: "inline" | "attachment";
    },
    options?: Options<never, ThrowOnError>,
  ) {
    const params = buildClientParams(
      [parameters],
      [
        {
          args: [
            { in: "path", key: "token" },
            { in: "path", key: "filename" },
            { in: "query", key: "disposition" },
          ],
        },
      ],
    );
    return (options?.client ?? client).get<
      DownloadAttachmentByTokenResponses,
      DownloadAttachmentByTokenErrors,
      ThrowOnError,
      "data"
    >({
      responseStyle: "data",
      url: "/v1/attachments/download/{token}/{filename}",
      ...options,
      ...params,
    });
  }
}

export class EventsService {
  /**
   * Subscribe to real-time events (SSE)
   *
   * Opens a Server-Sent Events stream delivering real-time notifications
   * for conversations the caller has access to. Events are cache-invalidation
   * hints — clients should refetch the affected resource on receipt.
   *
   * The response is `text/event-stream`. Each message is a JSON object:
   * `{"event":"<action>","kind":"<resource>","data":{...}}`
   */
  public static subscribeEvents<ThrowOnError extends boolean = true>(
    parameters?: {
      kinds?: string;
      after?: string;
      detail?: "summary" | "full";
      entry_channels?: string;
      entry_content_types?: string;
      entry_roles?: string;
    },
    options?: Options<never, ThrowOnError, SubscribeEventsResponse>,
  ) {
    const params = buildClientParams(
      [parameters],
      [
        {
          args: [
            { in: "query", key: "kinds" },
            { in: "query", key: "after" },
            { in: "query", key: "detail" },
            { in: "query", key: "entry_channels" },
            { in: "query", key: "entry_content_types" },
            { in: "query", key: "entry_roles" },
          ],
        },
      ],
    );
    return (options?.client ?? client).sse.get<SubscribeEventsResponses, SubscribeEventsErrors, ThrowOnError, "data">({
      responseStyle: "data",
      security: [{ scheme: "bearer", type: "http" }],
      url: "/v1/events",
      ...options,
      ...params,
    });
  }
}

